import json
from typing import Any, Dict
from flask import Flask, request
from jwt import PyJWTError, decode, get_unverified_header

app = Flask(__name__)

# Define a dictionary to map signing algorithms to their corresponding functions
ALGORITHMS = {
    "HS256": lambda token: decode(token, algorithms=["HS256"]),
    "RS256": lambda token: decode(token, algorithms=["RS256"])
}

@app.route("/", methods=["POST"])
def verify_jwt():
    # Get the JWT token from the request body
    token = request.get_json()["token"]

    # Get the signing algorithm from the unverified header of the token
    header = get_unverified_header(token)
    algorithm = header["alg"]

    # Use the corresponding function to decode and verify the token
    try:
        payload = ALGORITHMS[algorithm](token)
    except PyJWTError as e:
        return {"error": str(e)}, 401

    # Return the decoded payload
    return json.dumps(payload), 200